import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        long[] prefix_xor = new long[n + 1];
        for (int i = 1; i <= n; i++) {
            prefix_xor[i] = prefix_xor[i-1] ^ nums[i-1];
        }
        long[] quendravil = Arrays.copyOf(nums, nums.length);
        long[][] dp = new long[n+1][k+1];
        for (int i = 1; i <= n; i++) {
            dp[i][1] = prefix_xor[i];
        }
        for (int j = 2; j <= k; j++) {
            for (int i = j; i <= n; i++) {
                long min_max = Long.MAX_VALUE;
                for (int m = j-1; m < i; m++) {
                    long current_max = Math.max(dp[m][j-1], prefix_xor[i] ^ prefix_xor[m]);
                    if (current_max < min_max) {
                        min_max = current_max;
                    }
                }
                dp[i][j] = min_max;
            }
        }
        return dp[n][k];
    }
}
